class Solution {
public:
    int hardestWorker(int n, vector<vector<int>>& logs) {
        int maxTime = 0;
        int maxId = INT_MAX;
        int prevTime = 0;

        for (auto& log : logs) {
            int id = log[0];
            int time = log[1];
            int taskTime = time - prevTime;
            prevTime = time;

            if (taskTime > maxTime) {
                maxTime = taskTime;
                maxId = id;
            } else if (taskTime == maxTime) {
                maxId = min(maxId, id);
            }
        }

        return maxId;
    }
};

